module RefModule (  
    input wire [15:0] data_in,  
    input wire [3:0] addr,  
    input wire we,  
    input wire ce,  
    output reg [15:0] data_out  
);  
    reg [15:0] obf_memory [15:0];  

    always @(posedge ce) begin  
        if (we)  
            obf_memory[addr] <= data_in;  
        else  
            data_out <= obf_memory[addr];  
    end  
endmodule
